(() => {
const HOUSEHOLD_MEMBER_PAGE_SIZE = 8;
const state = { householdMembers: [], householdPage: 1, householdSearch: '' };
let currentPersonDetail = null;
function registerModal(id) {
const modal = document.querySelector('#' + id);
const service = window.Thon09Platform?.modals;
if (modal && service?.registerBootstrap) service.registerBootstrap(id, '#' + id);
return modal;
}
function openModal(id) {
const service = window.Thon09Platform?.modals;
if (service?.open && service.open(id)) return;
window.bootstrap?.Modal?.getOrCreateInstance?.(document.querySelector('#' + id))?.show();
}
function closeModal(id) {
const service = window.Thon09Platform?.modals;
if (service?.close && service.close(id)) return;
window.bootstrap?.Modal?.getOrCreateInstance?.(document.querySelector('#' + id))?.hide();
}
document.addEventListener('DOMContentLoaded', () => {
registerSprint8Actions();
ensureSprint8Modals();
patchImportGuide();
patchUserManagementUi();
});
document.addEventListener('thon09:auth-state', event => {
if (!event.detail?.authenticated) return;
registerSprint8Actions();
ensureSprint8Modals();
patchImportGuide();
patchUserManagementUi();
});
function registerSprint8Actions() {
const actions = window.Thon09Platform && window.Thon09Platform.actions;
if (window.__thon09Sprint8ActionsRegistered || !actions || typeof actions.register !== 'function') return;
window.__thon09Sprint8ActionsRegistered = true;
actions
.register('sprint8.person.edit', context => {
const id = Number(context.dataset.id || currentPersonDetail?.id || 0);
closeModal('personDetailModal');
if (id) openPersonForm(id);
})
.register('sprint8.person.print', () => {
if (currentPersonDetail) printPersonDetail(currentPersonDetail);
})
.register('sprint8.member.page', context => {
state.householdPage = Number(context.dataset.memberPage || 1);
renderHouseholdMembers();
});
}
window.showHousehold = async function showHousehold(id) {
try {
const household = await api('/api/households/' + id);
const members = await api('/api/persons?' + new URLSearchParams({ householdId: household.household_code, pageSize: 1000 }).toString());
state.householdMembers = members.items || [];
state.householdPage = 1;
state.householdSearch = '';
document.querySelector('#householdMemberSearch').value = '';
document.querySelector('#householdMemberTitle').textContent = 'Thành viên hộ ' + (household.household_code || '');
document.querySelector('#householdMemberMeta').innerHTML = details([
['Mã hộ', household.household_code], ['Chủ hộ', household.head_citizen_name], ['Địa chỉ', household.address], ['Số điện thoại', household.phone], ['Ở nhà', household.at_home_count || 0], ['Đi vắng', household.away_count || 0]
]);
renderHouseholdMembers();
openModal('householdMembersModal');
} catch (error) { showToast(error.message, 'danger'); }
};
window.showPerson = async function showPerson(id) {
try {
const row = await api('/api/persons/' + id);
currentPersonDetail = row;
document.querySelector('#personDetailTitle').textContent = row.full_name || 'Chi tiết nhân khẩu';
document.querySelector('#personDetailBody').innerHTML = personDetailHtml(row);
document.querySelector('#personDetailEditBtn').dataset.id = row.id || '';
document.querySelector('#personDetailPrintBtn').dataset.id = row.id || '';
openModal('personDetailModal');
} catch (error) { showToast(error.message, 'danger'); }
};
function ensureSprint8Modals() {
if (document.querySelector('#householdMembersModal')) {
registerModal('householdMembersModal');
registerModal('personDetailModal');
return;
}
document.body.insertAdjacentHTML('beforeend', '<div class="modal fade" id="householdMembersModal" tabindex="-1" aria-hidden="true"><div class="modal-dialog modal-xl modal-dialog-scrollable"><div class="modal-content"><div class="modal-header"><div><h5 id="householdMemberTitle" class="modal-title">Thành viên hộ</h5><small class="text-muted">Danh sách nhân khẩu cùng mã hộ</small></div><button type="button" class="btn-close" data-bs-dismiss="modal" aria-label="Đóng"></button></div><div class="modal-body"><div id="householdMemberMeta" class="mb-3"></div><div class="toolbar"><input id="householdMemberSearch" class="form-control" placeholder="Tìm họ tên, mã nhân khẩu, CCCD, số điện thoại"><button class="btn btn-light" type="button" data-bs-dismiss="modal">Đóng</button></div><div class="table-responsive"><table class="table table-hover align-middle"><thead><tr><th>Mã nhân khẩu</th><th>Họ tên</th><th>Ngày sinh</th><th>CCCD</th><th>Số điện thoại</th><th>Thường trú</th><th>Hiện tại</th><th></th></tr></thead><tbody id="householdMemberRows"></tbody></table></div><div id="householdMemberPager" class="pager"></div></div><div class="modal-footer"><button type="button" class="btn btn-light" data-bs-dismiss="modal">Đóng</button></div></div></div></div><div class="modal fade" id="personDetailModal" tabindex="-1" aria-hidden="true"><div class="modal-dialog modal-xl modal-dialog-scrollable"><div class="modal-content"><div class="modal-header"><h5 id="personDetailTitle" class="modal-title">Chi tiết nhân khẩu</h5><button type="button" class="btn-close" data-bs-dismiss="modal" aria-label="Đóng"></button></div><div id="personDetailBody" class="modal-body"></div><div class="modal-footer"><button id="personDetailEditBtn" class="btn btn-primary" type="button" data-platform-action="sprint8.person.edit">Sửa</button><button id="personDetailPrintBtn" class="btn btn-outline-secondary" type="button" data-platform-action="sprint8.person.print">In</button><button class="btn btn-light" type="button" data-bs-dismiss="modal">Đóng</button></div></div></div></div>');
document.querySelector('#householdMemberSearch').addEventListener('input', debounce(event => { state.householdSearch = event.target.value.trim().toLowerCase(); state.householdPage = 1; renderHouseholdMembers(); }, 250));
registerModal('householdMembersModal');
registerModal('personDetailModal');
}
function renderHouseholdMembers() {
const filtered = state.householdMembers.filter(row => !state.householdSearch || [row.citizen_code, row.full_name, row.identity_number, row.phone].join(' ').toLowerCase().includes(state.householdSearch));
const totalPages = Math.max(1, Math.ceil(filtered.length / HOUSEHOLD_MEMBER_PAGE_SIZE));
state.householdPage = Math.min(state.householdPage, totalPages);
const start = (state.householdPage - 1) * HOUSEHOLD_MEMBER_PAGE_SIZE;
const pageItems = filtered.slice(start, start + HOUSEHOLD_MEMBER_PAGE_SIZE);
document.querySelector('#householdMemberRows').innerHTML = pageItems.map(row => '<tr><td>' + escapeHtml(row.citizen_code || '') + '</td><td>' + escapeHtml(row.full_name || '') + '</td><td>' + formatDate(row.date_of_birth) + '</td><td>' + escapeHtml(row.identity_number || '') + '</td><td>' + escapeHtml(row.phone || '') + '</td><td>' + residencyLabel(row.residency_status) + '</td><td>' + presenceLabel(row.presence_status) + '</td><td class="text-end"><button class="btn btn-sm btn-outline-primary" type="button" data-platform-action="persons.detail" data-id="' + row.id + '">Xem chi tiết</button></td></tr>').join('') || emptyRow(8, 'Không có thành viên phù hợp');
document.querySelector('#householdMemberPager').innerHTML = '<span class="text-muted small">Trang ' + state.householdPage + '/' + totalPages + ' - ' + number(filtered.length) + ' thành viên</span><button class="btn btn-outline-secondary btn-sm" ' + (state.householdPage <= 1 ? 'disabled' : '') + ' data-platform-action="sprint8.member.page" data-member-page="' + (state.householdPage - 1) + '">Trước</button><button class="btn btn-outline-secondary btn-sm" ' + (state.householdPage >= totalPages ? 'disabled' : '') + ' data-platform-action="sprint8.member.page" data-member-page="' + (state.householdPage + 1) + '">Sau</button>';
}
function personDetailHtml(row) {
const photo = hasValue(row.photo_url) ? '<div class="person-detail-photo"><img src="' + escapeHtml(row.photo_url) + '" alt="Ảnh nhân khẩu"></div>' : '';
const fullName = valueText(row.full_name) || 'Nhân khẩu';
const citizenCode = valueText(row.citizen_code);
const identity = valueText(row.identity_number || row.personal_id || row.national_id);
const age = ageText(row.date_of_birth);
const statusBadges = [
badge(row.gender, 'neutral'),
Number(row.party_member) === 1 ? badge('Đảng viên', 'gold') : '',
isHouseholdHead(row) ? badge('Chủ hộ', 'green') : '',
row.residency_status === 'TEMPORARY' ? badge('Tạm trú', 'blue') : '',
row.presence_status === 'AWAY' ? badge('Tạm vắng', 'purple') : ''
].filter(Boolean).join('');
const basic = detailSection('Th\u00f4ng tin c\u01a1 b\u1ea3n', 'fa-id-card', [
['M\u00e3 h\u1ed9', row.household_code, 'code'],
['M\u00e3 nh\u00e2n kh\u1ea9u', row.citizen_code, 'code'],
['H\u1ecd v\u00e0 t\u00ean', row.full_name, 'strong'],
['Ng\u00e0y sinh', formatDate(row.date_of_birth)],
['Tu\u1ed5i', age],
['Gi\u1edbi t\u00ednh', row.gender],
['CCCD/S\u1ed1 \u0111\u1ecbnh danh', identity, 'code'],
['S\u1ed1 \u0111i\u1ec7n tho\u1ea1i', row.phone],
['\u0110\u1ecba ch\u1ec9 hi\u1ec7n t\u1ea1i', row.current_address || row.household_address]
]);
const residence = detailSection('Th\u00f4ng tin nh\u00e2n th\u00e2n v\u00e0 c\u01b0 tr\u00fa', 'fa-house-user', [
['Quan h\u1ec7 v\u1edbi ch\u1ee7 h\u1ed9', row.relationship],
['D\u00e2n t\u1ed9c', row.ethnicity],
['Ngh\u1ec1 nghi\u1ec7p', row.occupation],
['Tr\u00ecnh \u0111\u1ed9 h\u1ecdc v\u1ea5n', row.education_level],
['T\u00ecnh tr\u1ea1ng h\u00f4n nh\u00e2n', row.marital_status],
['C\u01b0 tr\u00fa', residencyLabel(row.residency_status)],
['Hi\u1ec7n t\u1ea1i', presenceLabel(row.presence_status)],
['Ch\u1ee7 h\u1ed9', row.head_citizen_name],
['H\u1ecd t\u00ean b\u1ed1', row.father_name || row.father_display_name],
['H\u1ecd t\u00ean m\u1eb9', row.mother_name || row.mother_display_name]
]);
const administrative = detailSection('Thông tin hành chính', 'fa-landmark', [
['Đảng viên', Number(row.party_member) === 1 ? 'Có' : ''],
['Đoàn viên Thanh niên', Number(row.youth_union_member) === 1 ? 'Có' : ''],
['Hội Phụ nữ', Number(row.women_union_member) === 1 ? 'Có' : ''],
['Hội Nông dân', Number(row.farmers_union_member) === 1 ? 'Có' : ''],
['Hội Cựu chiến binh', Number(row.veterans_union_member) === 1 ? 'Có' : ''],
['Hội Người cao tuổi', Number(row.elderly_union_member) === 1 ? 'Có' : ''],
['Đối tượng chính sách', policyLabels(row).join(', ')],
['Diện hộ', row.household_type],
['Trạng thái', lifeLabel(row.life_status)],
['Ngày đăng ký', formatDateTime(row.created_at)],
['Ghi chú', row.note]
]);
return '<div class="person-detail-card">'
+ '<div class="person-detail-hero">' + photo + '<div class="person-detail-identity"><span>Hồ sơ nhân khẩu</span><h3>' + escapeHtml(fullName) + '</h3><div class="person-detail-codes">' + (citizenCode ? '<strong>' + escapeHtml(citizenCode) + '</strong>' : '') + (identity ? '<strong>CCCD: ' + escapeHtml(identity) + '</strong>' : '') + '</div><div class="person-detail-badges">' + statusBadges + '</div></div></div>'
+ '<div class="person-detail-sections">' + [basic, residence, administrative].filter(Boolean).join('') + '</div>'
+ '</div>';
}
function hasValue(value) {
if (value === null || value === undefined) return false;
const text = String(value).trim();
return text !== '' && text !== '-' && text !== '—' && text.toLowerCase() !== 'null' && text.toLowerCase() !== 'undefined';
}
function valueText(value) { return hasValue(value) ? String(value).trim() : ''; }
function detailSection(title, icon, rows) {
const items = rows.filter(item => hasValue(item[1]));
if (!items.length) return '';
return '<section class="person-info-section"><div class="person-info-section-title"><i class="fa-solid ' + icon + '"></i><h4>' + escapeHtml(title) + '</h4></div><div class="person-info-grid">' + items.map(item => detailField(item[0], item[1], item[2])).join('') + '</div></section>';
}
function detailField(label, value, tone) {
const className = tone ? ' person-info-value-' + tone : '';
return '<div class="person-info-field"><span>' + escapeHtml(label) + '</span><strong class="person-info-value' + className + '">' + escapeHtml(valueText(value)) + '</strong></div>';
}
function badge(text, tone) { return hasValue(text) ? '<span class="person-detail-badge person-detail-badge-' + tone + '">' + escapeHtml(text) + '</span>' : ''; }
function isHouseholdHead(row) {
return String(row.relationship || '').trim().toLowerCase() === 'chủ hộ' || String(row.full_name || '').trim() === String(row.head_citizen_name || '').trim();
}
function ageText(value) {
if (!hasValue(value)) return '';
const date = new Date(String(value).replace(' ', 'T'));
if (Number.isNaN(date.getTime())) return '';
const now = new Date();
let age = now.getFullYear() - date.getFullYear();
const monthDiff = now.getMonth() - date.getMonth();
if (monthDiff < 0 || (monthDiff === 0 && now.getDate() < date.getDate())) age--;
return age >= 0 ? age + ' tuổi' : '';
}
function policyLabels(row) {
const labels = [];
if (Number(row.meritorious_person) === 1) labels.push('Người có công');
if (Number(row.martyr_relative) === 1) labels.push('Thân nhân liệt sĩ');
if (Number(row.wounded_soldier) === 1) labels.push('Thương binh');
if (Number(row.sick_soldier) === 1) labels.push('Bệnh binh');
if (Number(row.disabled_person) === 1) labels.push('Người khuyết tật');
if (Number(row.social_assistance) === 1) labels.push('Bảo trợ xã hội');
return labels;
}
function printPersonDetail(row) {
const win = window.open('', '_blank', 'width=1024,height=768');
win.document.write('<!doctype html><html lang="vi"><head><meta charset="utf-8"><title>' + escapeHtml(row.full_name || 'Nhân khẩu') + '</title><style>@page{size:A4;margin:14mm}body{font-family:"Segoe UI",Roboto,Arial,"Noto Sans",sans-serif;color:#111}.detail-grid{display:grid;grid-template-columns:1fr 1fr;gap:8px 16px}.detail-item{border-bottom:1px solid #ddd;padding:6px 0}.detail-label{font-size:12px;color:#555}.detail-value{font-weight:700}</style></head><body><h2>Phiếu thông tin nhân khẩu</h2>' + personDetailHtml(row) + '<script>window.print();<\\/script></body></html>');
win.document.close();
}
function patchImportGuide() {
const screen = document.querySelector('#importScreen');
if (screen) screen.dataset.sprint8 = '1';
}
function patchUserManagementUi() {
const screen = document.querySelector('#usersScreen');
if (!screen || screen.dataset.sprint8) return;
screen.dataset.sprint8 = '1';
const head = screen.querySelector('thead tr');
if (head) head.innerHTML = '<th>Username</th><th>Họ tên</th><th>Email</th><th>Số điện thoại</th><th>Chức vụ</th><th>Vai trò</th><th>Trạng thái</th><th>Ngày tạo</th><th>Lần đăng nhập cuối</th><th></th>';
const modalBody = document.querySelector('#userForm .modal-body');
if (modalBody) modalBody.innerHTML = '<input type="hidden" name="id"><div class="row g-3"><div class="col-md-6"><label class="form-label">Username</label><input name="username" class="form-control" required></div><div class="col-md-6"><label class="form-label">Email</label><input name="email" type="email" class="form-control" required></div><div class="col-md-6"><label class="form-label">Họ tên</label><input name="displayName" class="form-control" required></div><div class="col-md-6"><label class="form-label">Số điện thoại</label><input name="phone" class="form-control"></div><div class="col-md-6"><label class="form-label">Chức vụ</label><input name="position" class="form-control"></div><div class="col-md-6"><label class="form-label">Vai trò</label><select name="role" class="form-select"><option value="ADMIN">Admin</option><option value="OFFICER">Cán bộ</option><option value="VIEWER">Khách</option></select></div><div class="col-12"><label class="form-label">Mật khẩu</label><input name="password" type="password" class="form-control" minlength="8"><div class="form-text">Bắt buộc khi tạo mới, để trống nếu không đổi.</div></div></div>';
window.openUserForm = async function openUserForm(id = null) {
const form = document.querySelector('#userForm');
form.reset(); form.elements.id.value = ''; form.elements.email.disabled = false; form.elements.username.disabled = false;
if (id) { const row = await api('/api/users/' + id); setForm(form, { id: row.id, username: row.username, email: row.email, displayName: row.displayName, phone: row.phone, position: row.position, role: row.role === 'SUPER_ADMIN' ? 'ADMIN' : row.role }); form.elements.email.disabled = true; form.elements.username.disabled = true; }
openModal('userModal');
};
}
window.renderUserRowsSprint8 = function renderUserRowsSprint8(data) {
const body = document.querySelector('#userRows');
if (!body) return;
body.innerHTML = data.items.map(row => { const action = row.status === 'ACTIVE' ? 'lock' : 'unlock'; return '<tr><td>' + escapeHtml(row.username || '') + '</td><td>' + escapeHtml(row.display_name || row.displayName || '') + '</td><td>' + escapeHtml(row.email || '') + '</td><td>' + escapeHtml(row.phone || '') + '</td><td>' + escapeHtml(row.position || '') + '</td><td>' + roleLabel(row.role) + '</td><td>' + statusLabel(row.status) + '</td><td>' + formatDateTime(row.created_at) + '</td><td>' + formatDateTime(row.last_login_at) + '</td><td class="text-end"><button class="btn btn-sm btn-outline-primary" type="button" data-platform-action="users.edit" data-id="' + row.id + '">Sửa</button> <button class="btn btn-sm btn-outline-warning" type="button" data-platform-action="users.toggle" data-id="' + row.id + '" data-action="' + action + '">' + (action === 'lock' ? 'Khóa' : 'Mở khóa') + '</button> <button class="btn btn-sm btn-outline-secondary" type="button" data-platform-action="users.resetPassword" data-id="' + row.id + '">Đặt lại mật khẩu</button> <button class="btn btn-sm btn-outline-danger" type="button" data-platform-action="users.delete" data-id="' + row.id + '">Xóa</button></td></tr>'; }).join('') || emptyRow(10, 'Chưa có người dùng');
};
window.resetUserPassword = async function resetUserPassword(id) {
const password = prompt('Nhập mật khẩu mới tối thiểu 8 ký tự');
if (!password) return;
if (password.length < 8) return showToast('Mật khẩu tối thiểu 8 ký tự', 'warning');
const row = await api('/api/users/' + id);
await api('/api/users/' + id, { method: 'PUT', body: { displayName: row.displayName, role: row.role, phone: row.phone, position: row.position, password } });
showToast('Đã đặt lại mật khẩu');
};
function formatDateTime(value) { if (!value) return ''; const date = new Date(String(value).replace(' ', 'T')); return Number.isNaN(date.getTime()) ? formatDate(value) : date.toLocaleString('vi-VN'); }
function statusLabel(status) { return status === 'ACTIVE' ? 'Hoạt động' : status === 'INACTIVE' ? 'Đã khóa' : status || ''; }
})();
